previewCss:
.darma-loader-darma-custom-295 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #f97316);
  background: linear-gradient(90deg,var(--loader-color, #f97316),var(--loader-secondary-color, #facc15)) text;
  animation: darma-loader-darma-custom-295-l8 2s linear infinite;
}
.darma-loader-darma-custom-295:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-295-l8 {
  0%,2%,8%,11%,15%,21%,30%,32%,35%,40%,46%,47%,53%,61%,70%,72%,77%,80%,86%   {background-size: 0    0   }
  1%,9%,10%,16%,20%,31%,34%,41%,45%,48%,52%,55%,60%,73%,76%,81%,85%,96%,100% {background-size: 100% 100%}
}

